-- PSGC City Barangays Seed
-- Generated: 2026-06-20T13:07:26.502Z
-- Total city barangays: 21259

create table if not exists barangays (
  id uuid primary key default uuid_generate_v4(),
  psgc_code text unique,
  name text not null,
  city_psgc_code text not null,
  city_name text not null,
  created_at timestamptz default now()
);
create index if not exists idx_barangays_city_psgc on barangays(city_psgc_code);
alter table barangays enable row level security;
create policy "Barangays publicly readable" on barangays for select using (true);











































